function pad(n) { return String(n).padStart(2, '0'); }

function getLocalParts(dateTimeStr, timezone) {
  const dt = new Date(dateTimeStr);
  const f = new Intl.DateTimeFormat('en-US', {
    timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit', weekday: 'long'
  });
  const parts = f.formatToParts(dt);
  const p = {};
  parts.forEach(x => { p[x.type] = x.value; });
  return {
    year: parseInt(p.year), month: parseInt(p.month), day: parseInt(p.day),
    localDate: p.year + '-' + p.month + '-' + p.day, dayOfWeek: p.weekday
  };
}

function observedDate(year, month, day) {
  const dow = new Date(year, month - 1, day).getDay();
  if (dow === 6) { const f = new Date(year, month - 1, day - 1); return { year: f.getFullYear(), month: f.getMonth() + 1, day: f.getDate() }; }
  if (dow === 0) { const f = new Date(year, month - 1, day + 1); return { year: f.getFullYear(), month: f.getMonth() + 1, day: f.getDate() }; }
  return null;
}

function toKey(o) { return o.year + '-' + pad(o.month) + '-' + pad(o.day); }

function nthWeekday(year, month, weekday, n) {
  let count = 0;
  for (let d = 1; d <= 31; d++) {
    const dt = new Date(year, month - 1, d);
    if (dt.getMonth() !== month - 1) break;
    if (dt.getDay() === weekday && ++count === n) return { year, month, day: d };
  }
}

function lastWeekday(year, month, weekday) {
  let result = null;
  for (let d = 1; d <= 31; d++) {
    const dt = new Date(year, month - 1, d);
    if (dt.getMonth() !== month - 1) break;
    if (dt.getDay() === weekday) result = { year, month, day: d };
  }
  return result;
}

function buildHolidayMap(year) {
  const h = {};
  function addFixed(month, day, name) {
    const actual = { year, month, day };
    h[toKey(actual)] = name;
    const obs = observedDate(year, month, day);
    if (obs) h[toKey(obs)] = name + ' (observed)';
  }
  function addFloat(o, name) { if (o) h[toKey(o)] = name; }
  addFixed(1, 1, "New Year's Day");
  addFixed(6, 19, "Juneteenth");
  addFixed(7, 4, "Independence Day");
  addFixed(11, 11, "Veterans Day");
  addFixed(12, 25, "Christmas Day");
  addFloat(nthWeekday(year, 1, 1, 3), "MLK Day");
  addFloat(nthWeekday(year, 2, 1, 3), "Presidents Day");
  addFloat(lastWeekday(year, 5, 1), "Memorial Day");
  addFloat(nthWeekday(year, 9, 1, 1), "Labor Day");
  addFloat(nthWeekday(year, 10, 1, 2), "Columbus Day");
  addFloat(nthWeekday(year, 11, 4, 4), "Thanksgiving");
  if (new Date(year + 1, 0, 1).getDay() === 6) {
    const k = year + '-12-31';
    if (!h[k]) h[k] = "New Year's Day (observed, next year)";
  }
  return h;
}

// UNCHANGED: nextBusinessDay — start from day+1 and go forward
function nextBusinessDay(year, month, day) {
  let d = new Date(Date.UTC(year, month - 1, day + 1));
  for (let i = 0; i < 14; i++) {
    const y = d.getUTCFullYear(), m = d.getUTCMonth() + 1, dd = d.getUTCDate();
    const key = y + '-' + pad(m) + '-' + pad(dd);
    const hmap = { ...buildHolidayMap(y - 1), ...buildHolidayMap(y), ...buildHolidayMap(y + 1) };
    if (d.getUTCDay() !== 0 && d.getUTCDay() !== 6 && !hmap[key]) return key;
    d.setUTCDate(d.getUTCDate() + 1);
  }
  return 'unknown';
}

// NEW: previousBusinessDay — start from day-1 and go backward
// Used for 24h meeting reminders: if reminder falls on weekend/holiday,
// move to the previous business day so the reminder is not missed.
function previousBusinessDay(year, month, day) {
  let d = new Date(Date.UTC(year, month - 1, day - 1));
  for (let i = 0; i < 14; i++) {
    const y = d.getUTCFullYear(), m = d.getUTCMonth() + 1, dd = d.getUTCDate();
    const key = y + '-' + pad(m) + '-' + pad(dd);
    const hmap = { ...buildHolidayMap(y - 1), ...buildHolidayMap(y), ...buildHolidayMap(y + 1) };
    if (d.getUTCDay() !== 0 && d.getUTCDay() !== 6 && !hmap[key]) return key;
    d.setUTCDate(d.getUTCDate() - 1);
  }
  return 'unknown';
}

const input = $input.first().json;
const { mode, testCases, tzWarning, dtWarning } = input;
const results = [];

for (const tc of testCases) {
  const { label, dateTime, timezone } = tc;
  const { year, month, day, localDate, dayOfWeek } = getLocalParts(dateTime, timezone);
  const hmap = { ...buildHolidayMap(year - 1), ...buildHolidayMap(year), ...buildHolidayMap(year + 1) };
  const isWeekend = dayOfWeek === 'Saturday' || dayOfWeek === 'Sunday';
  const holidayName = hmap[localDate] || null;
  const isHoliday = !!holidayName;
  const isBusinessDay = !isWeekend && !isHoliday;
  let reason;
  if (isHoliday && isWeekend) reason = 'US federal holiday (falls on weekend)';
  else if (isHoliday) reason = 'US federal holiday: ' + holidayName;
  else if (isWeekend) reason = 'Weekend';
  else reason = 'Normal business day';
  // UNCHANGED: nextBusinessDay — same as before
  const nbd = isBusinessDay ? localDate : nextBusinessDay(year, month, day);
  // NEW: previousBusinessDay — goes backward to nearest business day
  const pbd = isBusinessDay ? localDate : previousBusinessDay(year, month, day);
  const out = { mode, timezoneUsed: timezone, localDate, dayOfWeek, isWeekend, isHoliday, holidayName: holidayName || 'none', isBusinessDay, nextBusinessDay: nbd, previousBusinessDay: pbd, reason };
  if (mode === 'manual') out.label = label;
  if (tzWarning) out.tzWarning = tzWarning;
  if (dtWarning) out.dtWarning = dtWarning;
  results.push({ json: out });
}

return results;

// Called mode only — fires from Execute Sub-workflow Trigger.
// Errors if dateTime is missing.
// Warns if dateTime has no timezone offset or Z suffix.
// Warns if timezone is missing (defaults to America/New_York).
// Errors if timezone is unsupported.

const SUPPORTED_TIMEZONES = [
  'America/New_York','America/Chicago','America/Denver','America/Los_Angeles'
];

const item = $input.first().json;
const rawDateTime = (item.dateTime || '').toString().trim();
const rawTimezone = (item.timezone || '').toString().trim();

// Error: dateTime missing
if (!rawDateTime) {
  return [{ json: {
    mode: 'called',
    error: true,
    errorMessage: 'dateTime is required when calling W11 from another workflow. Pass an ISO string with timezone offset, e.g. 2026-07-04T09:00:00-04:00 or 2026-07-04T13:00:00Z'
  }}];
}

// Warning: dateTime has no offset or Z
const hasOffset = /Z$|[+-]\d{2}:\d{2}$/.test(rawDateTime);
const dtWarning = hasOffset
  ? null
  : 'dateTime has no timezone offset or Z suffix — result may be ambiguous. Recommended format: 2026-07-04T09:00:00-04:00 or 2026-07-04T13:00:00Z';

// Timezone handling
let timezone = rawTimezone || 'America/New_York';
const tzWarning = rawTimezone
  ? null
  : 'timezone not provided — defaulted to America/New_York';

// Error: unsupported timezone
if (!SUPPORTED_TIMEZONES.includes(timezone)) {
  return [{ json: {
    mode: 'called',
    error: true,
    errorMessage: 'Unsupported timezone: ' + timezone + '. Supported: ' + SUPPORTED_TIMEZONES.join(', ')
  }}];
}

return [{ json: {
  mode: 'called',
  error: false,
  tzWarning: tzWarning || null,
  dtWarning: dtWarning || null,
  testCases: [{ label: 'Called input', dateTime: rawDateTime, timezone }]
}}];

// Manual mode only — fires from Run Business-Day Utility Manually trigger.
// Always returns 12 hardcoded 2026+2027 test cases.
// Ignores any input.

return [{ json: {
  mode: 'manual',
  error: false,
  tzWarning: null,
  dtWarning: null,
  testCases: [
    { label: '2026-TC1: July 4 2026 (Sat) — New York',              dateTime: '2026-07-04T12:00:00', timezone: 'America/New_York'   },
    { label: '2026-TC2: July 4 2026 (Sat) — Los Angeles',           dateTime: '2026-07-04T12:00:00', timezone: 'America/Los_Angeles' },
    { label: '2026-TC3: Christmas 2026 (Fri) — Chicago',            dateTime: '2026-12-25T12:00:00', timezone: 'America/Chicago'    },
    { label: '2026-TC4: Normal Tuesday Jul 7 2026 — Denver',        dateTime: '2026-07-07T12:00:00', timezone: 'America/Denver'     },
    { label: '2026-TC5: Saturday Jul 11 2026 — New York',           dateTime: '2026-07-11T12:00:00', timezone: 'America/New_York'   },
    { label: '2026-TC6: Sunday Jul 12 2026 — Los Angeles',          dateTime: '2026-07-12T12:00:00', timezone: 'America/Los_Angeles' },
    { label: "2027-TC7: New Year's Day Jan 1 2027 (Fri) — New York",dateTime: '2027-01-01T12:00:00', timezone: 'America/New_York'   },
    { label: '2027-TC8: Jul 5 2027 (observed Mon for Jul 4) — Chicago', dateTime: '2027-07-05T12:00:00', timezone: 'America/Chicago' },
    { label: '2027-TC9: Dec 24 2027 (observed Fri for Dec 25) — Denver', dateTime: '2027-12-24T12:00:00', timezone: 'America/Denver' },
    { label: '2027-TC10: Normal Wed Mar 10 2027 — Los Angeles',     dateTime: '2027-03-10T12:00:00', timezone: 'America/Los_Angeles' },
    { label: '2027-TC11: Saturday Aug 7 2027 — New York',           dateTime: '2027-08-07T12:00:00', timezone: 'America/New_York'   },
    { label: '2027-TC12: Sunday Sep 5 2027 — Los Angeles',          dateTime: '2027-09-05T12:00:00', timezone: 'America/Los_Angeles' }
